<header class="page-head"><div><span class="eyebrow">Tampilan / Identitas</span><h1>Identitas merek</h1></div></header><form method="post" enctype="multipart/form-data" action="<?=url('/admin/appearance/branding')?>" class="editor-grid"><?=csrf_field()?><section class="panel stack"><h2>Logo dan ikon</h2><label>Logo utama<input type="file" name="branding_logo" accept="image/jpeg,image/png,image/webp"><small>PNG transparan atau WebP, maksimal 2 MB.</small></label><?php if(!empty($settings['branding_logo'])):?><img class="media-preview" src="<?=url('/media/branding/'.$settings['branding_logo'])?>" alt="Logo saat ini"><?php endif?><label>Logo terang untuk latar gelap<input type="file" name="branding_logo_light" accept="image/jpeg,image/png,image/webp"></label><label>Favicon<input type="file" name="branding_favicon" accept="image/png,image/webp,image/x-icon"><small>Persegi 32–512 px, maksimal 512 KB.</small></label><label>Alt text logo<input name="branding_logo_alt" value="<?=e($settings['branding_logo_alt']??setting('store_name'))?>" maxlength="120"></label></section><aside class="stack"><section class="panel stack"><h2>Penampilan logo</h2><label>Lebar logo desktop<input type="number" min="80" max="320" name="branding_logo_width" value="<?=e($settings['branding_logo_width']??180)?>"></label><label class="check"><input type="checkbox" name="branding_show_name" value="1" <?=($settings['branding_show_name']??'1')==='1'?'checked':''?>> Tampilkan nama toko</label><h2>SEO dasar</h2><label>Judul browser<input name="branding_meta_title" maxlength="160" value="<?=e($settings['branding_meta_title']??setting('store_name'))?>"></label><label>Meta description<textarea name="branding_meta_description" maxlength="300"><?=e($settings['branding_meta_description']??setting('store_tagline'))?></textarea></label><button class="button button-large">Simpan identitas</button></section></aside></form>
